4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (underpopulation, rule 1)", () => {
12	    expect(nextGeneration([[0, 0], [0, 1]])).toEqual([]);
13	  });
14	  it("should keep a block stable (still life)", () => {
15	    const block: Array<[number, number]> = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(new Set(result.map(c => `${c[0]},${c[1]}`))).toEqual(
18	      new Set(block.map(c => `${c[0]},${c[1]}`))
19	    );
20	  });
21	  it.todo("should let a live cell with 3 neighbors survive (rule 2)");
22	  it.todo("should kill a live cell with more than 3 neighbors (rule 3, overpopulation)");
23	  it.todo("should bring a dead cell with exactly 3 neighbors to life (rule 4, reproduction)");
24	  it.todo("should oscillate a vertical blinker to a horizontal blinker");
