1	type Cell = [number, number];
2	
3	function cellKey(x: number, y: number): string {
4	  return `${x},${y}`;
5	}
6	
7	function parseCellKey(key: string): Cell {
8	  const [x, y] = key.split(",").map(Number);
9	  return [x, y];
10	}
11	
12	export function nextGeneration(cells: Array<Cell>): Array<Cell> {
13	  const aliveKeys = new Set(cells.map(([x, y]) => cellKey(x, y)));
14	  const neighborCounts = new Map<string, number>();
15	
16	  for (const [x, y] of cells) {
17	    for (let dx = -1; dx <= 1; dx++) {
18	      for (let dy = -1; dy <= 1; dy++) {
19	        if (dx === 0 && dy === 0) continue;
20	        const key = cellKey(x + dx, y + dy);
21	        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
22	      }
23	    }
24	  }
25	
26	  const survivors: Array<Cell> = [];
27	  for (const [key, count] of neighborCounts) {
28	    const isAlive = aliveKeys.has(key);
29	    const willLive = isAlive ? count === 2 || count === 3 : count === 3;
30	    if (willLive) survivors.push(parseCellKey(key));
31	  }
32	
33	  return survivors;
34	}
